using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;

// --- Configuration -----------------------------------------------------------
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Tools -------------------------------------------------------------------
var notebook = new ResearchNotebook();
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

var tools = new AITool[]
{
    AIFunctionFactory.Create(
        ([Description("The search query to look up on the web")] string query) =>
            WebSearchAsync(httpClient, query),
        "web_search",
        "Searches the web for the given query and returns a list of result titles, snippets, and URLs. Use this to gather information on a research topic."),

    AIFunctionFactory.Create(
        ([Description("A concise title for the note")] string title,
         [Description("The content to save")] string content) =>
        {
            notebook.Add(title, content);
            return $"Note saved: \"{title}\"";
        },
        "save_note",
        "Saves a research note with a title and content. Use this to record key findings while researching."),

    AIFunctionFactory.Create(
        () => notebook.GetAll(),
        "get_notes",
        "Returns all previously saved research notes so you can review what has been collected."),
};

// --- Agent -------------------------------------------------------------------
IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant. When the user gives you a topic:
        1. Search the web 2-3 times with varied queries to gather broad information.
        2. Save the most important findings as notes using the save_note tool.
        3. After researching, retrieve your notes and write a well-structured summary
           with key facts, organized under clear headings.
        Be thorough but concise. Always cite sources when possible.
        """,
    name: "ResearchAgent",
    description: "An AI agent that researches topics by searching the web and summarizing findings.",
    tools: tools);

// --- Run ---------------------------------------------------------------------
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║        Research Agent (MAF + MEAI)       ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.WriteLine();

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine();
Console.WriteLine($"Researching: {topic}");
Console.WriteLine(new string('─', 50));

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
});

await using var session = await agent.CreateSessionAsync();

await foreach (var update in agent.RunStreamingAsync(
    topic, session, runOptions))
{
    Console.Write(update.Text);
}

Console.WriteLine();
Console.WriteLine(new string('─', 50));
Console.WriteLine($"Research complete. {notebook.Count} note(s) collected.");

// --- Web search implementation -----------------------------------------------
static async Task<string> WebSearchAsync(HttpClient http, string query)
{
    // Uses the DuckDuckGo Instant Answer API (no key required)
    var encoded = Uri.EscapeDataString(query);
    var url = $"https://html.duckduckgo.com/html/?q={encoded}";

    try
    {
        var request = new HttpRequestMessage(HttpMethod.Get, url);
        var response = await http.SendAsync(request);
        response.EnsureSuccessStatusCode();
        var html = await response.Content.ReadAsStringAsync();

        // Parse result snippets from the HTML response
        var results = ParseDuckDuckGoResults(html);
        if (results.Count == 0)
        {
            return $"No results found for: {query}";
        }

        return string.Join("\n\n", results.Take(5));
    }
    catch (Exception ex)
    {
        return $"Search failed for \"{query}\": {ex.Message}";
    }
}

static List<string> ParseDuckDuckGoResults(string html)
{
    var results = new List<string>();

    // Extract result blocks from DuckDuckGo HTML
    var snippetMarker = "result__snippet";
    var titleMarker = "result__a";

    var pos = 0;
    while (pos < html.Length && results.Count < 5)
    {
        // Find title
        var titleIdx = html.IndexOf($"class=\"{titleMarker}\"", pos, StringComparison.Ordinal);
        if (titleIdx < 0) break;

        var titleStart = html.IndexOf('>', titleIdx) + 1;
        var titleEnd = html.IndexOf("</a>", titleStart, StringComparison.Ordinal);
        if (titleStart <= 0 || titleEnd < 0) break;

        var title = StripHtmlTags(html[titleStart..titleEnd]).Trim();

        // Find href
        var hrefIdx = html.LastIndexOf("href=\"", titleIdx, Math.Min(titleIdx, 200), StringComparison.Ordinal);
        var href = "";
        if (hrefIdx >= 0)
        {
            var hrefStart = hrefIdx + 6;
            var hrefEnd = html.IndexOf('"', hrefStart);
            if (hrefEnd > hrefStart)
            {
                href = html[hrefStart..hrefEnd];
                if (href.StartsWith("//duckduckgo.com/l/?uddg="))
                {
                    href = Uri.UnescapeDataString(
                        href.Replace("//duckduckgo.com/l/?uddg=", ""));
                    var ampIdx = href.IndexOf('&');
                    if (ampIdx > 0) href = href[..ampIdx];
                }
            }
        }

        // Find snippet
        var snippetIdx = html.IndexOf($"class=\"{snippetMarker}\"", titleEnd, StringComparison.Ordinal);
        var snippet = "";
        if (snippetIdx >= 0 && snippetIdx < titleEnd + 500)
        {
            var snippetStart = html.IndexOf('>', snippetIdx) + 1;
            var snippetEnd = html.IndexOf("</a>", snippetStart, StringComparison.Ordinal);
            if (snippetEnd < 0)
                snippetEnd = html.IndexOf("</td>", snippetStart, StringComparison.Ordinal);
            if (snippetStart > 0 && snippetEnd > snippetStart)
            {
                snippet = StripHtmlTags(html[snippetStart..snippetEnd]).Trim();
            }
            pos = Math.Max(snippetEnd, titleEnd) + 1;
        }
        else
        {
            pos = titleEnd + 1;
        }

        if (!string.IsNullOrWhiteSpace(title))
        {
            results.Add($"Title: {title}\nURL: {href}\nSnippet: {snippet}");
        }
    }

    return results;
}

static string StripHtmlTags(string html)
{
    var output = new System.Text.StringBuilder(html.Length);
    var inTag = false;
    foreach (var ch in html)
    {
        if (ch == '<') { inTag = true; continue; }
        if (ch == '>') { inTag = false; continue; }
        if (!inTag) output.Append(ch);
    }
    return System.Net.WebUtility.HtmlDecode(output.ToString());
}

// --- Notebook ----------------------------------------------------------------
class ResearchNotebook
{
    private readonly List<(string Title, string Content, DateTime Timestamp)> _notes = [];

    public void Add(string title, string content)
        => _notes.Add((title, content, DateTime.UtcNow));

    public string GetAll()
        => _notes.Count == 0
            ? "No notes saved yet."
            : string.Join("\n\n", _notes.Select((n, i) =>
                $"[{i + 1}] {n.Title} ({n.Timestamp:HH:mm:ss UTC})\n{n.Content}"));

    public int Count => _notes.Count;
}

